sql:
SELECT section_name, SUM(current_students) AS total_current_students
FROM sections
GROUP BY section_name;

external_knowledge:
; Average final grade is calculated by summing all final grades and dividing by the total number of grades; 
; The final grade is converted to a real number to allow for arithmetic operations; 
; A course section is a combination of a course and a section (e.g., Math course, Section A).

sql:
SELECT course_name, credits
FROM courses
ORDER BY credits DESC;

SELECT DISTINCT course_name
FROM courses
WHERE semester = 'Fall 2023';
